# phytron.proto
# StreamDevice protocol file for Phytron MCC-1 MINI-W-ETH over TCP/IP.
#
# IMPORTANT COMMISSIONING NOTES
# - The MCC-1 uses framed packets, not generic plain-text commands.
# - Observed working traffic used STX/ETX framing:
#     TX example: 02 30 58 50 32 30 52 03
#     RX example: 02 06 31 30 30 03
# - Address handling is critical. Previous non-working code used address 1,
#   while a working case used address 0.
# - The exact command bytes for all required operations are NOT fully specified
#   by the provided evidence. Therefore this file uses a verified framing style,
#   preserves the exact required protocol block names, and marks placeholder
#   command bytes clearly for commissioning.
# - Replace/verify the address byte(s) and command payloads against real MCC-1
#   protocol documentation or packet captures before operational use.
#
# VERIFIED BY PROVIDED EVIDENCE
# - STX = 0x02
# - ETX = 0x03
# - Framed byte-oriented command style is correct
# - Address value must be checked during commissioning; observed working case
#   suggests address 0 rather than 1
#
# PLACEHOLDERS IN THIS FILE
# - Command payload bytes for position read, speed read, move+, move-, stop
#   are scaffolds and must be verified against the real MCC-1 command set.
# - Input parsing for numeric values may need adjustment once actual reply
#   payload layouts are confirmed.

Terminator = "";
ExtraInput = Ignore;
ReplyTimeout = 1000;
ReadTimeout = 1000;
WriteTimeout = 1000;
PollPeriod = 500;

# Shared notes:
# - The examples below use a default address character of '0' (0x30) because
#   the context indicates address 0 worked where address 1 failed.
# - If your controller is configured differently, change the address byte in
#   each frame accordingly during commissioning.
# - StreamDevice sends raw framed strings here using \x02 ... \x03.

getPosition {
    # Placeholder command bytes using verified frame style only.
    # Address handling must be checked here. Current scaffold uses address '0'.
    # Command payload "XP20R" is inspired by observed traffic style and is NOT
    # fully verified as the real position-read command.
    out "\x02" "0XP20R" "\x03";
    # Expected reply shape is not fully verified. This reads a framed numeric
    # body after a possible status byte. Adjust once real reply bytes are known.
    in  "\x02%*1r%f\x03";
}

getSpeed {
    # Placeholder command bytes using verified frame style only.
    # Address handling must be checked here. Current scaffold uses address '0'.
    # "XSPDR" is a placeholder mnemonic in framed MCC-1 style and MUST be
    # replaced if packet captures/documentation show a different command.
    out "\x02" "0XSPDR" "\x03";
    in  "\x02%*1r%f\x03";
}

movePlus {
    # Placeholder command bytes using verified frame style only.
    # Address handling must be checked here. Current scaffold uses address '0'.
    # "XMVP" is a placeholder motion command mnemonic and is NOT verified.
    out "\x02" "0XMVP" "\x03";
    # Accept any framed acknowledgement during bring-up.
    in  "\x02%*[^"]";
}

moveMinus {
    # Placeholder command bytes using verified frame style only.
    # Address handling must be checked here. Current scaffold uses address '0'.
    # "XMVM" is a placeholder motion command mnemonic and is NOT verified.
    out "\x02" "0XMVM" "\x03";
    # Accept any framed acknowledgement during bring-up.
    in  "\x02%*[^"]";
}

stopMotion {
    # Placeholder command bytes using verified frame style only.
    # Address handling must be checked here. Current scaffold uses address '0'.
    # "XSTP" is a placeholder stop command mnemonic and is NOT verified.
    out "\x02" "0XSTP" "\x03";
    # Accept any framed acknowledgement during bring-up.
    in  "\x02%*[^"]";
}
